const messages = $.steps.fetchEmails.response.messages || [];
const maxEmails = $.input.maxEmails || 10;
return { messageIds: messages.map(m => m.id).filter(Boolean).slice(0, maxEmails) };

const iterations = $.steps.fetchDetails.response.iterations || [];
let compiled = '';
let emailCount = 0;

iterations.forEach((iter, i) => {
  if (!iter.getMsg || !iter.getMsg.response) return;
  const msg = iter.getMsg.response;
  const headers = msg.payload ? (msg.payload.headers || []) : [];
  const getHeader = (name) => { const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase()); return h ? h.value : ''; };

  const from = getHeader('From');
  const subject = getHeader('Subject');
  const date = getHeader('Date');

  let body = '';
  if (msg.payload && msg.payload.body && msg.payload.body.data) {
    try { body = Buffer.from(msg.payload.body.data, 'base64').toString('utf8'); } catch(e) { body = ''; }
  } else if (msg.payload && msg.payload.parts) {
    const textPart = msg.payload.parts.find(p => p.mimeType === 'text/plain');
    if (textPart && textPart.body && textPart.body.data) {
      try { body = Buffer.from(textPart.body.data, 'base64').toString('utf8'); } catch(e) { body = ''; }
    }
  }
  if (!body) body = msg.snippet || '';

  compiled += '--- EMAIL ' + (i + 1) + ' ---\n';
  compiled += 'From: ' + from + '\n';
  compiled += 'Subject: ' + subject + '\n';
  compiled += 'Date: ' + date + '\n';
  compiled += 'Body: ' + body.slice(0, 2000) + '\n\n';
  emailCount++;
});

return { compiled: compiled.slice(0, 25000), emailCount };

const d = $.steps.compileEmails.output;
const tone = $.input.replyTone || 'professional and friendly';
const context = $.input.companyContext || '';

let prompt = 'You are a customer communication specialist. Draft reply suggestions for each of the following emails.\n\n';
prompt += 'REPLY TONE: ' + tone + '\n';
if (context) prompt += 'COMPANY CONTEXT: ' + context + '\n';
prompt += '\nEMAILS TO REPLY TO (' + d.emailCount + ' emails):\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Draft a concise, helpful reply for each email\n';
prompt += '- Match the specified tone\n';
prompt += '- Categorize each email: inquiry, complaint, request, FYI, spam\n';
prompt += '- Rate urgency: high, medium, low\n';
prompt += '- For spam or newsletters, suggest "no reply needed"\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "replies": [\n';
prompt += '    {\n';
prompt += '      "emailNumber": 1,\n';
prompt += '      "from": "sender",\n';
prompt += '      "subject": "subject line",\n';
prompt += '      "category": "inquiry|complaint|request|fyi|spam",\n';
prompt += '      "urgency": "high|medium|low",\n';
prompt += '      "draftReply": "the suggested reply text",\n';
prompt += '      "replyNeeded": true\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "summary": "brief summary of inbox status"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { replies: [], summary: raw }; }

const ai = $.steps.parseAI.output;
const emailCount = $.steps.compileEmails.output.emailCount;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Inbox Reply Drafts', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Emails processed:* ' + emailCount + (ai.summary ? '\n' + ai.summary : '') } });
blocks.push({ type: 'divider' });

(ai.replies || []).forEach((r, i) => {
  const urgencyIcon = r.urgency === 'high' ? ':red_circle:' : r.urgency === 'low' ? ':white_circle:' : ':large_yellow_circle:';
  const catIcon = r.category === 'complaint' ? ':warning:' : r.category === 'spam' ? ':no_entry:' : r.category === 'request' ? ':raising_hand:' : ':email:';

  let text = urgencyIcon + ' ' + catIcon + ' *Email ' + r.emailNumber + ': ' + (r.subject || 'No subject') + '*\n';
  text += '_From:_ ' + (r.from || 'Unknown') + ' | _Category:_ ' + (r.category || 'unknown') + ' | _Urgency:_ ' + (r.urgency || 'medium') + '\n\n';

  if (r.replyNeeded === false) {
    text += ':no_bell: No reply needed';
  } else {
    text += '*Suggested Reply:*\n> ' + (r.draftReply || 'No draft generated').split('\n').join('\n> ');
  }

  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Draft replies for review | Powered by Gmail + Claude AI | One CLI' }] });

const fallback = 'Inbox Drafts: ' + emailCount + ' emails processed - ' + (ai.summary || '').slice(0, 100);
return { blocks, fallback };
